def ordered_onering_halfedges(he_mesh, V_he, vtx_id):
    first_he = V_he[vtx_id]
    cur_he = first_he
    
    ring_halfedges = []
    new_he=True
    while new_he:
        
        ring_halfedges.append(he_mesh.half_edges[ cur_he ].next)
        cur_he = he_mesh.half_edges[ he_mesh.half_edges[ cur_he ].twin ].next
        if cur_he == first_he:
            new_he=False
            
    return ring_halfedges[::-1]



def onering_halfedges_with_radials(he_mesh, V_he, vtx_id):
    first_he = V_he[vtx_id]
    cur_he = first_he
    
    ring_halfedges = []
    new_he=True
    while new_he:

        ring_halfedges.append(cur_he) # also include radials
        
        ring_halfedges.append(he_mesh.half_edges[ cur_he ].next)
        cur_he = he_mesh.half_edges[ he_mesh.half_edges[ cur_he ].twin ].next

        if cur_he == first_he:
            new_he=False
            
    return ring_halfedges[::-1]



def ordered_radial_halfedges(he_mesh, V_he, vtx_id):
    first_he = V_he[vtx_id]
    cur_he = first_he
    
    ring_halfedges = []
    new_he=True
    while new_he:

        ring_halfedges.append(cur_he) # also include radials
        
        #ring_halfedges.append(he_mesh.half_edges[ cur_he ].next)
        cur_he = he_mesh.half_edges[ he_mesh.half_edges[ cur_he ].twin ].next

        if cur_he == first_he:
            new_he=False
            
    return ring_halfedges[::-1]


    

def he_mesh_from_file(mesh_filepath):
    mesh_o3d = o3d.io.read_triangle_mesh(mesh_filepath)
    mesh_o3d.compute_vertex_normals()
    he_mesh = o3d.geometry.HalfEdgeTriangleMesh.create_from_triangle_mesh(mesh_o3d)

    V_he = get_V_he(he_mesh)
    
    return he_mesh, V_he


def he_mesh_from_o3d(mesh_o3d):
    
    he_mesh = o3d.geometry.HalfEdgeTriangleMesh.create_from_triangle_mesh(mesh_o3d)
    V_he = get_V_he(he_mesh)
    
    return he_mesh, V_he

def o3d_mesh_from_file(mesh_filepath):
    
    mesh_o3d = o3d.io.read_triangle_mesh(mesh_filepath)
    return mesh_o3d


def o3d_mesh_from_he_mesh(he_mesh):
    mesh = o3d.geometry.TriangleMesh()
    mesh.vertices = o3d.utility.Vector3dVector(np.asarray(he_mesh.vertices))
    mesh.triangles = o3d.utility.Vector3iVector(np.asarray(he_mesh.triangles))
    return mesh
    

def get_V_he(he_mesh):

    print('Preparing V_he for halfedge mesh')

    V_he = [-1] * len(he_mesh.vertices)  # More efficient than list comprehension

    for i, he in enumerate(he_mesh.half_edges):
        if i % 10000 == 0 and i!=0:
            print(i, 'of', len(he_mesh.half_edges))
    
        V_he[he.vertex_indices[0]] = i  # Direct attribute access

    print('Prepared V_he for halfedge mesh.')
    print()

    return V_he



def optimise_V_he(he_mesh, V_he):
    """
    Assigns each vertex a boundary halfedge if the vertex is on a boundary.
    For interior vertices, keeps the original V_he.
    """

    he = he_mesh.half_edges
    print('Optimising V_he.')

    for i, he_id_0 in enumerate(V_he):
        he_id = he_id_0
        start_he = he_id_0
        found_boundary = False

        while True:
            if he[he_id].twin == -1:
                # this halfedge is a boundary, assign it to V_he
                V_he[i] = he_id
                found_boundary = True
                break

            # move to next halfedge around the vertex
            he_id = he[he[he_id].twin].next

            if he_id == start_he:
                # looped around, no boundary halfedge found
                break

        # Optional: if not found_boundary, V_he[i] remains unchanged

    print('Finished optimising V_he.\n')
    return V_he


    





































