        #onering_halfedges = onering_halfedges_with_radials(he_mesh, V_he, vtx_id)
        onering_halfedges = ordered_onering_halfedges(he_mesh, V_he, vtx_id)
        

        count=0
        for j in onering_halfedges:
            
            a = he_mesh.vertices[he_mesh.half_edges[j].vertex_indices[0]]
            b = he_mesh.vertices[he_mesh.half_edges[j].vertex_indices[1]]
            
            if debug_plot:
                plt.plot([a[0], b[0]], [a[1], b[1]], color='black')
                plt.text(a[0], a[1], str(he_mesh.half_edges[j].vertex_indices[1]), fontsize=9, ha='left', va='bottom', color='black')

                
                plt.scatter([q[0]], [q[1]], color = 'orange')
                plt.text(q[0], q[1], 'q', fontsize=9, ha='left', va='bottom', color='orange')

