                plt.scatter(he_mesh.vertices[vtx_id][0], he_mesh.vertices[vtx_id][1], color='blue', alpha=0.5)
                #plt.text(vx[0], vx[1], f'vtx {vtx_id}', fontsize=9, ha='left', va='bottom', color='blue')

