def cut_mesh_along_geodesic_v2(he_mesh, V_he, geodesic_filepath, bdry_halfedge_mask, first_vtx_id, last_vtx_id, left_face_id=1, right_face_id=1, debug_plot=False, verbose=False):

    geodesic = trimesh.load(geodesic_filepath)
    geodesic_points = geodesic.vertices

    
    # Convert vertices to Open3D point cloud
    geodesic_pcd = o3d.geometry.PointCloud()
    geodesic_pcd.points = o3d.utility.Vector3dVector(geodesic_points)



    
    
    vertices = he_mesh.vertices  # or however you access the vertex array
    
    # Build KDTree
    tree = cKDTree(vertices)
    
    # Query nearest vertex for each point
    distances, indices = tree.query(geodesic_points)

    #plt.plot(distances)
    #plt.show()

    first_vtx_id = indices[0]

    #print(geodesic_points)
    remaining_geodesic_points = list(geodesic_points)

    print('Starting the cutting for a curve. First and last vertex id are', first_vtx_id, last_vtx_id )

    while len(remaining_geodesic_points) > 0:
        if verbose:
            print('Making a cut...')

        vertex_indices, remaining_geodesic_points, bdry_halfedge_mask = do_mesh_cutting(he_mesh, V_he, remaining_geodesic_points, bdry_halfedge_mask, geodesic_pcd, first_vtx_id, left_face_id=left_face_id, right_face_id=right_face_id, debug_plot=debug_plot, verbose=verbose)

        first_vtx_id = vertex_indices[-1]
        if verbose:
            print('now first vtx id is', first_vtx_id)
            print(len(remaining_geodesic_points), 'remaining')

    print('Cut along a curve successfully')

    return he_mesh, V_he, geodesic_pcd, vertex_indices, bdry_halfedge_mask







def do_mesh_cutting_v3(he_mesh, V_he, geodesic_points, bdry_halfedge_mask, geodesic_pcd, first_vtx_id, left_face_id=1, right_face_id=1, debug_plot=False, verbose=False):



    edge_id = None
    ended = False
    vtx_id = first_vtx_id
    vertex_indices = [vtx_id]

